namespace sv_c122cbd6631b45c081a944c284f541eb.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@* A single channel row: # name, description snippet, unread badge *@

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired]
    public Channel Channel { get; set; } = default!;

    [Parameter]
    public bool IsActive { get; set; }

    [Parameter]
    public EventCallback<int> OnChannelSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 50
            ? Channel.Description[..50] + "…"
            : Channel.Description;

    private async Task HandleClick() => await OnChannelSelected.InvokeAsync(Channel.Id);
}

.channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 6px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.channel-item.active .channel-name {
    color: #fff;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.78rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@* Reusable textarea + send/reply button *@

<div class="message-input-area">
    <textarea class="message-textarea"
              placeholder="@Placeholder"
              @bind="text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              rows="2"></textarea>
    <button class="send-button" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter]
    public string Placeholder { get; set; } = "Type a message…";

    [Parameter]
    public string ButtonLabel { get; set; } = "Send";

    [Parameter]
    public EventCallback<string> OnSend { get; set; }

    private string text = string.Empty;

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(text)) return;
        var content = text.Trim();
        text = string.Empty;
        await OnSend.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-textarea:focus {
    border-color: #4a90d9;
}

.send-button {
    padding: 8px 18px;
    background-color: #4a90d9;
    color: #fff;
    border: none;
    border-radius: 8px;
    cursor: pointer;
    font-weight: 600;
    font-size: 0.85rem;
    transition: background-color 0.15s;
    white-space: nowrap;
}

.send-button:hover:not(:disabled) {
    background-color: #357abd;
}

.send-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@* A single message: author, timestamp, content, reactions, hover actions *@

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="() => { showActions = false; showEmojiPicker = false; }">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions-row">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
                💬 Reply
            </button>
            <button class="action-btn" title="Add reaction" @onclick="() => showEmojiPicker = !showEmojiPicker">
                🙂 React
            </button>
        </div>

        @if (showEmojiPicker)
        {
            <div class="emoji-picker">
                @foreach (var emoji in commonEmojis)
                {
                    <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message Message { get; set; } = default!;

    [Parameter]
    public int ThreadReplyCount { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    /// <summary>Passes (messageId, emoji)</summary>
    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        showActions = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.92rem;
    color: #1a1a1a;
}

.message-time {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    color: #333;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #ddd;
    border-radius: 12px;
    background: #f0f0f0;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #dbeafe;
    border-color: #93c5fd;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    font-size: 0.8rem;
    color: #4a90d9;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.action-btn {
    padding: 4px 10px;
    border: none;
    background: transparent;
    cursor: pointer;
    font-size: 0.78rem;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background-color: #f0f0f0;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 170px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    z-index: 11;
}

.emoji-btn {
    padding: 4px 6px;
    border: none;
    background: transparent;
    cursor: pointer;
    font-size: 1.2rem;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.emoji-btn:hover {
    background-color: #f0f0f0;
}

