toolArgs.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.92rem;
    color: #1a1a1a;
}

.message-time {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    color: #333;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #ddd;
    border-radius: 12px;
    background: #f0f0f0;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #dbeafe;
    border-color: #93c5fd;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    font-size: 0.8rem;
    color: #4a90d9;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    z-index: 10;
