arguments.file_text:
namespace sv_c122cbd6631b45c081a944c284f541eb.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@* Left sidebar: channel list with active highlighting *@

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnChannelSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int ActiveChannelId { get; set; }

    [Parameter]
    public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    background-color: #2c2f33;
    color: #e0e0e0;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@* Scrollable message list with load-more on scroll-to-top *@

<div class="message-list" @onscroll="HandleScroll" @ref="scrollContainer">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }

    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ThreadReplyCount="GetThreadReplyCount(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Message> Messages { get; set; } = [];

    [Parameter]
    public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];

    [Parameter]
    public bool IsLoadingMore { get; set; }

    [Parameter]
    public EventCallback OnLoadMore { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference scrollContainer;
    private bool loadMoreRequested;

    private int GetThreadReplyCount(int messageId) =>
        ThreadReplyCounts.GetValueOrDefault(messageId);

    private async Task HandleScroll()
    {
        // Trigger load-more when scrolled near the top
        if (!IsLoadingMore && !loadMoreRequested)
        {
            loadMoreRequested = true;
            await OnLoadMore.InvokeAsync();
            loadMoreRequested = false;
        }
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.82rem;
    color: #888;
}

@* Main message area: header, message list, input *@

<div class="message-area">
    @if (CurrentChannel is not null)
    {
        <div class="area-header">
            <h2># @CurrentChannel.Name</h2>
            <span class="area-description">@CurrentChannel.Description</span>
        </div>

        <MessageList Messages="Messages"
                     ThreadReplyCounts="ThreadReplyCounts"
                     IsLoadingMore="IsLoadingMore"
                     OnLoadMore="OnLoadMore"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />

        <MessageInput Placeholder="@($"Message #{CurrentChannel.Name}")"
                      ButtonLabel="Send"
                      OnSend="OnSendMessage" />
    }
    else
    {
        <div class="empty-state">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter]
    public Channel? CurrentChannel { get; set; }

    [Parameter]
    public List<Message> Messages { get; set; } = [];

    [Parameter]
    public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];

    [Parameter]
    public bool IsLoadingMore { get; set; }

    [Parameter]
    public EventCallback OnLoadMore { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    [Parameter]
    public EventCallback<string> OnSendMessage { get; set; }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #1a1a1a;
}

.area-description {
    font-size: 0.82rem;
    color: #777;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 1rem;
}

@* Collapsible thread panel: original message, replies, reply input *@

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter]
    public Message? RootMessage { get; set; }

    [Parameter]
    public List<Message> Replies { get; set; } = [];

    [Parameter]
    public EventCallback OnClose { get; set; }

    [Parameter]
    public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background-color: #f0f0f0;
    color: #333;
}

.thread-root-message {
    padding: 12px 16px;
    background-color: #f9f9f9;
    border-bottom: 1px solid #eee;
    flex-shrink: 0;
}

.root-author {
    font-weight: 700;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.root-content {
    font-size: 0.88rem;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: #999;
    border-bottom: 1px solid #eee;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
    gap: 8px;
    align-items: baseline;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.72rem;
    color: #999;
}

.reply-content {
    font-size: 0.85rem;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

