@page "/chat"
@using sv_c122cbd6631b45c081a944c284f541eb.Services
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-column">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannelAsync" />
    </div>

    <div class="main-column @(threadRootMessage is null ? "full-width" : "")">
        <MessageArea CurrentChannel="CurrentChannel"
                     Messages="messages"
                     ThreadReplyCounts="threadReplyCounts"
                     IsLoadingMore="isLoadingMore"
                     OnLoadMore="LoadMoreMessagesAsync"
                     OnOpenThread="OpenThreadAsync"
                     OnReact="HandleReactionAsync"
                     OnSendMessage="SendMessageAsync" />
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="thread-column">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReplyAsync" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private int selectedChannelId;
    private bool isLoadingMore;

    // Thread state
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private const int PageSize = 30;

    private Channel? CurrentChannel =>
        channels.FirstOrDefault(c => c.Id == selectedChannelId);

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0].Id);
        }
    }

    private async Task SelectChannelAsync(int channelId)
    {
        selectedChannelId = channelId;
        messages = await ChatService.GetMessagesAsync(channelId, skip: 0, take: PageSize);
        threadReplyCounts = await BuildThreadReplyCountsAsync();

        await ChatService.MarkChannelReadAsync(channelId);
        RefreshChannelUnread(channelId);
    }

    private async Task LoadMoreMessagesAsync()
    {
        if (isLoadingMore) return;

        isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(selectedChannelId, skip: messages.Count, take: PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            var additionalCounts = await BuildThreadReplyCountsAsync(older);
            foreach (var kvp in additionalCounts)
            {
                threadReplyCounts[kvp.Key] = kvp.Value;
            }
        }
        isLoadingMore = false;
    }

    private async Task SendMessageAsync(string content)
    {
        var sent = await ChatService.SendMessageAsync(selectedChannelId, content, replyToId: null);
        messages.Add(sent);
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        var allThread = await ChatService.GetThreadAsync(rootMessageId);
        // Exclude the root message from replies
        threadReplies = allThread.Where(m => m.Id != rootMessageId).ToList();
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, replyToId: threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread reply count in main view
        threadReplyCounts[threadRootMessage.Id] = threadReplies.Count;
    }

    private async Task HandleReactionAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh the message list to show updated reactions
        messages = await ChatService.GetMessagesAsync(selectedChannelId, skip: 0, take: messages.Count);
    }

    private void RefreshChannelUnread(int channelId)
    {
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = channels[idx];
            channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    private async Task<Dictionary<int, int>> BuildThreadReplyCountsAsync(List<Message>? subset = null)
    {
        var source = subset ?? messages;
        var counts = new Dictionary<int, int>();
        // Messages without a ReplyToId that might be thread roots
        foreach (var msg in source.Where(m => m.ReplyToId is null))
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            var replyCount = thread.Count(t => t.Id != msg.Id);
            if (replyCount > 0)
            {
                counts[msg.Id] = replyCount;
            }
        }
        return counts;
    }
}

